/* === ANIMATION SUITE v2 === */
!function(){"use strict";
if(typeof window==="undefined")return;
// Mark JS alive so opacity:0 gating in CSS applies only when we can animate
try{document.documentElement.classList.add("js-anim");}catch(e){}
// Generic .anim observer
var els=document.querySelectorAll(".anim, .anim-stagger, .gold-underline, .anim-blur");
if("IntersectionObserver"in window && els.length){
  var io=new IntersectionObserver(function(entries){
    entries.forEach(function(e){
      if(e.isIntersecting){
        e.target.classList.add("in");
        io.unobserve(e.target);
      }
    });
  },{threshold:.12,rootMargin:"0px 0px -60px 0px"});
  els.forEach(function(el){io.observe(el);});
  // Safety fallback: after 2.5s, force any still-hidden anim elements to .in
  setTimeout(function(){
    document.querySelectorAll(".anim:not(.in), .anim-stagger:not(.in), .anim-blur:not(.in)").forEach(function(el){el.classList.add("in");});
    document.querySelectorAll(".anim-fade-up:not(.visible)").forEach(function(el){el.classList.add("visible");});
  },2500);
  // Also handle bfcache restore (mobile Safari/Chrome back-forward)
  window.addEventListener("pageshow",function(ev){
    if(ev.persisted){
      document.querySelectorAll(".anim:not(.in), .anim-stagger:not(.in), .anim-blur:not(.in)").forEach(function(el){el.classList.add("in");});
      document.querySelectorAll(".anim-fade-up:not(.visible)").forEach(function(el){el.classList.add("visible");});
    }
  });
} else {
  els.forEach(function(el){el.classList.add("in");});
  document.querySelectorAll(".anim-fade-up").forEach(function(el){el.classList.add("visible");});
}
// Hover halo - mouse tracking
document.querySelectorAll(".hover-halo").forEach(function(c){
  c.addEventListener("mousemove",function(ev){
    var r=c.getBoundingClientRect();
    c.style.setProperty("--mx",(ev.clientX-r.left)+"px");
    c.style.setProperty("--my",(ev.clientY-r.top)+"px");
  });
});
// Lightweight parallax on bg elements
var pxEls=document.querySelectorAll("[data-parallax]");
if(pxEls.length){
  var ticking=false;
  function update(){
    pxEls.forEach(function(el){
      var rate=parseFloat(el.getAttribute("data-parallax"))||.15;
      var r=el.getBoundingClientRect();
      var off=(window.innerHeight/2 - (r.top+r.height/2))*rate;
      el.style.transform="translate3d(0,"+off.toFixed(1)+"px,0)";
    });
    ticking=false;
  }
  window.addEventListener("scroll",function(){
    if(!ticking){requestAnimationFrame(update);ticking=true;}
  },{passive:true});
  update();
}
// Body scroll lock when mobile nav open
var ham=document.getElementById("hamburger"), nav=document.getElementById("mainNav");
if(ham && nav){
  var mo=new MutationObserver(function(){
    if(nav.classList.contains("nav-open")) document.body.classList.add("nav-locked");
    else document.body.classList.remove("nav-locked");
  });
  mo.observe(nav,{attributes:true,attributeFilter:["class"]});
}
}();
